const item = $input.first();
let raw = '';

if (item.binary?.data?.data) {
  raw = Buffer.from(item.binary.data.data, 'base64').toString('utf8');
} else if (typeof item.json === 'string') {
  raw = item.json;
} else if (item.json?.content) {
  raw = item.json.content;
} else {
  raw = JSON.stringify(item.json || {});
}

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  throw new Error(`Uploaded export file is not valid JSON: ${error.message}`);
}

const workflows = Array.isArray(parsed)
  ? parsed
  : Array.isArray(parsed.workflows)
    ? parsed.workflows
    : Array.isArray(parsed.data)
      ? parsed.data
      : (parsed.name && parsed.nodes ? [parsed] : []);

if (workflows.length === 0) {
  throw new Error('No workflows found in export file. Upload an n8n workflow export JSON file.');
}

const date = new Date().toISOString().slice(0, 10);

return workflows
  .filter(workflow => workflow && workflow.name && Array.isArray(workflow.nodes))
  .map(workflow => {
    const safeName = workflow.name
      .replace(/[\\/:*?"<>|]/g, '-')
      .replace(/\s+/g, '_')
      .replace(/_+/g, '_')
      .trim();

    return {
      json: {
        workflow_id: workflow.id || null,
        workflow_name: workflow.name,
        filename: `workflows/${safeName}.json`,
        content: JSON.stringify(workflow, null, 2),
        commit_message: `Backup: ${workflow.name} - ${date}`,
        backup_date: date,
        source_file_id: $('Google Drive Trigger').item.json.id,
        source_file_name: $('Google Drive Trigger').item.json.name
      }
    };
  });

let backedUp = [];
try {
  backedUp = $('Parse Export File').all().map(item => ({
    workflow_id: item.json.workflow_id,
    workflow_name: item.json.workflow_name,
    path: item.json.filename
  }));
} catch (e) {
  backedUp = [];
}

const first = $('Parse Export File').first().json;

return [{
  json: {
    backed_up_count: backedUp.length,
    failures_count: 0,
    backed_up_workflows: backedUp,
    source_file_id: first.source_file_id,
    source_file_name: first.source_file_name,
    backup_date: new Date().toISOString()
  }
}];
